import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { entityPrimitiveConstrainedRule } from "./entity-primitive-constrained.rule.js";

describe("entity-primitive-constrained rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, entityPrimitiveConstrainedRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_entity_primitive_constrained
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_entity_primitive_constrained:Products.A10nBlueprintEngine.Features.DomainAuthoring.entity_primitive_constrained:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_op_invariant_cap:Products.A10nBlueprintEngine.Features.DomainAuthoring.entity_primitive_constrained:must
    it("bare string field with @pattern constraint — valid", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task {
              @pattern("[a-z]+")
              id: string;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_02
    it("bare int32 field with @minValue constraint — valid", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task {
              @minValue(0)
              priority: int32;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_03
    it("bare string field referenced by @invariant predicate — valid", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task { id: string; }
          }
          using Products.MyProduct.Entities.Task;

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "A {@Task.id} is non-empty.",
              why: "Reason.",
            })
            op task_has_id(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_04
    it("enum field — not a bare primitive, not checked", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task { status: TaskStatus; }
            enum TaskStatus { pending, running }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_05
    it("bare string field with @maxLength constraint — valid", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task {
              @maxLength(255)
              name: string;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_06
    it("bare string field with @format constraint — valid", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task {
              @format("uuid")
              id: string;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_11
    it("utcDateTime field with no decorator and no invariant ref — valid (datetime excluded from bare-primitive check)", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.TaskRevision {
            @entity
            model TaskRevision {
              created_at: utcDateTime;
            }
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_07
    it("bare string field with no constraint and no invariant ref — reports", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task { id: string; }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/entity-primitive-constrained",
          message: /id/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_08
    it("bare int32 field with no constraint and no invariant ref — reports", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task { priority: int32; }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/entity-primitive-constrained",
          message: /priority/,
        });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_09
    it("multiple bare primitive fields, none constrained — reports all", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Orphan {
            @entity
            model Orphan { id: string; count: int32; }
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/entity-primitive-constrained", message: /id/ },
          { code: "@a10n/blueprint-typespec/entity-primitive-constrained", message: /count/ },
        ]);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T011.T011_10
    it("bare boolean field with no constraint and no invariant ref — reports", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task { active: boolean; }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/entity-primitive-constrained",
          message: /active/,
        });
    });
  });
});
